INSERT INTO public.techniques (code, name, belt, category, hip_er_min, hip_ir_min, hip_abd_min, hip_flex_min, shoulder_er_min, ankle_df_min, lumbar_flex_min, thoracic_rot_min, notes) VALUES
  ('BT10', 'Circle Throw (Tomoenage)', 'blue', 'Throws', 50.0, NULL, NULL, NULL, NULL, 15.0, NULL, NULL, 'GREEN if used value >= 15 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Sacrifice throw — hip flex <110 → inadequate foot placement; lumbar flex <30 → disc injury; failed throw → compromised supine position. Confidence: MEDIUM'),
  ('BT11', 'Single-to-Double Leg Chain', 'blue', 'Throws', NULL, NULL, NULL, NULL, NULL, 20.0, NULL, NULL, 'GREEN if used value >= 20 (LEAD side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Highest cumulative standing ROM demand — multi-phase execution; ankle DF <10 → knee valgus during transition. Confidence: LOW'),
  ('BT12', 'Pulling Guard to Open Guard', 'blue', 'Throws', 55.0, NULL, NULL, NULL, NULL, 15.0, NULL, NULL, 'GREEN if used value >= 15 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Rapid standing→supine → lumbar compression if opponent drives; hip ER <45 → valgus on hooking leg. Confidence: MEDIUM'),
  ('BT4', 'High Crotch Single Leg', 'blue', 'Throws', NULL, NULL, NULL, NULL, NULL, 20.0, NULL, NULL, 'GREEN if used value >= 20 (LEAD side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Ankle DF <10 → ACL risk on penetration step; lumbar flex <30 → cervical compensation; head-inside → cervical extension critical. Confidence: MEDIUM'),
  ('BT5', 'Low Single Leg / Ankle Pick', 'blue', 'Throws', NULL, NULL, NULL, NULL, NULL, 20.0, NULL, NULL, 'GREEN if used value >= 20 (LEAD side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Deepest level change — lumbar flex <30 → high L4/L5 disc load; ankle DF <10 → patellofemoral load. Confidence: MEDIUM'),
  ('BT6', 'Blast Double Leg', 'blue', 'Throws', NULL, NULL, NULL, NULL, NULL, 20.0, NULL, NULL, 'GREEN if used value >= 20 (LEAD side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Cervical ext <40 → axial compression risk; ankle DF <10 → reduced penetration depth. Confidence: MEDIUM'),
  ('BT7', 'Snatch Double Leg (Head Outside)', 'blue', 'Throws', NULL, NULL, NULL, NULL, NULL, 20.0, NULL, NULL, 'GREEN if used value >= 20 (LEAD side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Head-outside → combined cervical lateral flex + rotation under load (whiplash mechanism). Confidence: MEDIUM'),
  ('BT8', 'Minor Inner Reap (Kouchigari)', 'blue', 'Throws', 45.0, NULL, NULL, NULL, NULL, 15.0, NULL, NULL, 'GREEN if used value >= 15 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Ankle inversion risk if DF <10 → ATFL sprain; hip ER <40 → compensatory knee torsion. Confidence: MEDIUM'),
  ('BT9', 'Major Inner Reap (Ouchigari)', 'blue', 'Throws', 45.0, NULL, NULL, NULL, NULL, 15.0, NULL, NULL, 'GREEN if used value >= 15 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Hip ext <20 → lumbar hyperextension; valgus knee if ER <40; high head rotational acceleration. Confidence: MEDIUM'),
  ('WT1', 'Major Hip Throw (O Goshi)', 'white', 'Throws', 45.0, NULL, NULL, NULL, NULL, 10.0, NULL, NULL, 'GREEN if used value >= 10 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: <60° hip flex OR <40° hip ER = Very High Risk; lumbar ext <20° risky for 30+'),
  ('WT2', 'Floating Hip Throw (Uki Goshi)', 'white', 'Throws', 55.0, NULL, NULL, NULL, NULL, 10.0, NULL, NULL, 'GREEN if used value >= 10 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: <45° hip rotation = Very High Risk; lumbar ext <20° risky for 30+'),
  ('WT3', 'Single Leg Takedown', 'white', 'Throws', NULL, NULL, NULL, NULL, NULL, 15.0, NULL, NULL, 'GREEN if used value >= 15 (LEAD side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: <10° ankle DF = DELAY TECHNIQUE (ACL/MCL risk)'),
  ('WT4', 'Double Leg Takedown', 'white', 'Throws', NULL, NULL, NULL, NULL, NULL, 15.0, NULL, NULL, 'GREEN if used value >= 15 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: <70° hip flex = excessive knee valgus; 30+ use modified entry if spinal flex <30°'),
  ('WT5', 'Foot Sweep', 'white', 'Throws', NULL, NULL, NULL, NULL, NULL, 15.0, NULL, NULL, 'GREEN if used value >= 15 (ANY side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Minimal ROM demands; timing-based technique'),
  ('BP1', 'Kneeling Closed Guard Break', 'blue', 'Passes', NULL, 40.0, NULL, NULL, NULL, 20.0, NULL, NULL, 'GREEN if used value >= 20 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Ankle DF <10 → anterior impingement; hip IR <30 → valgus knee stress on wedge; lumbar ext <20 → vulnerable to sweeps. Confidence: MEDIUM'),
  ('BP10', 'X-Guard Leg Weave Pass', 'blue', 'Passes', NULL, 40.0, NULL, NULL, NULL, 15.0, NULL, NULL, 'GREEN if used value >= 15 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Hip IR + flex simultaneous demand on weaving leg; IR <30 → medial knee stress during threading. Confidence: LOW'),
  ('BP11', 'Leg Lasso Leg Pin Pass', 'blue', 'Passes', NULL, 40.0, NULL, NULL, 65.0, 15.0, NULL, NULL, 'GREEN if used value >= 15 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Shoulder ER <60 → RC strain from forced rotation against lasso; elbow hyperextension risk if balance lost. Confidence: LOW'),
  ('BP12', 'Leg Lasso Backstep Pass', 'blue', 'Passes', 55.0, 40.0, NULL, NULL, 65.0, 15.0, NULL, NULL, 'GREEN if used value >= 15 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Same ER/IR split as BP9 plus shoulder ER to extract trapped arm; ER <50 traps passer in lasso. Confidence: LOW'),
  ('BP13', 'Butterfly Guard Floating Pass', 'blue', 'Passes', NULL, 40.0, NULL, NULL, NULL, 15.0, NULL, NULL, 'GREEN if used value >= 15 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: IR <30 → knee valgus on landing; timing-critical — failure to clear hooks → swept. Confidence: MEDIUM'),
