  ('BP15', 'Over/Under Pass', 'blue', 'Passes', NULL, 40.0, NULL, NULL, NULL, 20.0, NULL, NULL, 'GREEN if used value >= 20 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Asymmetric shoulder loading; shoulder flex <150 → impingement on over arm; hip flex <100 → lumbar rounding. Confidence: MEDIUM'),
  ('BP16', '50/50 Guard Pass', 'blue', 'Passes', 55.0, 40.0, NULL, NULL, NULL, 15.0, NULL, NULL, 'GREEN if used value >= 15 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Highest combined hip rotation of any pass; ER <50 traps in entanglement; 12% ↑ knee injury in heel-hook-legal comp. Confidence: MEDIUM'),
  ('BP17', 'Half Guard Cross-Face Smash Pass', 'blue', 'Passes', NULL, 40.0, NULL, NULL, NULL, 15.0, NULL, NULL, 'GREEN if used value >= 15 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Hip IR <30 → valgus during windshield-wiper extraction; shoulder flex for cross-face reach. Confidence: MEDIUM'),
  ('BP18', 'Half Guard Shoulder of Justice Pass', 'blue', 'Passes', 50.0, 40.0, NULL, NULL, NULL, 15.0, NULL, NULL, 'GREEN if used value >= 15 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Shoulder flex <150 → reduced pressure + compensatory cervical strain; ER <45 on trail leg → can''t hip-switch free. Confidence: MEDIUM'),
  ('BP19', 'Deep Half Guard Pass', 'blue', 'Passes', NULL, 40.0, NULL, NULL, NULL, 15.0, NULL, NULL, 'GREEN if used value >= 15 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Elevated lumbar ext demand (30°) — must resist being loaded from below; hip ext <20 → can''t sprawl deep enough. Confidence: LOW'),
  ('BP2', 'Log Splitter Guard Break', 'blue', 'Passes', NULL, 40.0, NULL, NULL, 65.0, 20.0, NULL, NULL, 'GREEN if used value >= 20 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Shoulder ER <60 → RC strain during forearm wedge; same ankle/IR risks as BP1. Confidence: LOW'),
  ('BP20', 'Lockdown Pass', 'blue', 'Passes', NULL, 40.0, NULL, NULL, NULL, 20.0, NULL, NULL, 'GREEN if used value >= 20 (LEAD side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Lockdown entangles leg — hip ext <25 makes extraction extremely difficult; ankle DF <15 → anterior tibialis strain; MCL/meniscus risk if forced. Confidence: LOW'),
  ('BP3', 'Standing Hip Push Guard Break', 'blue', 'Passes', NULL, 35.0, NULL, NULL, NULL, 15.0, NULL, NULL, 'GREEN if used value >= 15 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Ankle DF <10 → balance compromised during stand-up; shoulder flex <150 → forward lean exposes to sweeps. Confidence: MEDIUM'),
  ('BP4', 'Body Lock Pass', 'blue', 'Passes', NULL, 40.0, NULL, NULL, NULL, 15.0, NULL, NULL, 'GREEN if used value >= 15 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Hip IR <30 → valgus knee during windshield-wiper; lumbar ext <20 → can''t maintain chest pressure. Confidence: MEDIUM'),
  ('BP5', 'Smash Pass (Pressure Pass)', 'blue', 'Passes', NULL, 40.0, NULL, NULL, NULL, 15.0, NULL, NULL, 'GREEN if used value >= 15 (BOTH side) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Hip IR <30 → valgus loading on lead knee; requires coordinated IR/ER hip switching. Confidence: MEDIUM'),
