  ('WG6', 'X Guard', 'white', 'Guards', 65.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'GREEN if used value >= 40 (midline, no laterality) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: <60° hip ER OR <50° hip abd = OMIT for low-mobility adults (multi-joint stress)'),
  ('BS1', 'Hip Bump Sweep', 'blue', 'Sweeps', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'GREEN if used value >= 45 (midline, no laterality) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Lumbar ext <20 → reduced bump power + cervical hyperextension compensation; eccentric lumbar strain on failed attempt. Confidence: MEDIUM'),
  ('BS3', 'Sit-Up Sweep (Kimura Grip)', 'blue', 'Sweeps', NULL, NULL, NULL, NULL, 65.0, NULL, NULL, NULL, 'GREEN if used value >= 45 (midline, no laterality) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Shoulder ER <60 → RC strain under kimura grip load; same sit-up risks as BS1. Confidence: MEDIUM'),
  ('WS7', 'X Guard Sweep (Technical Stand-Up Sweep)', 'white', 'Sweeps', 65.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'GREEN if used value >= 45 (midline, no laterality) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: <60° hip ER OR <50° hip abd = OMIT if ER <45° (high knee/hip risk)'),
  ('WS8', 'Half Guard Sweep (Underhook Sweep)', 'white', 'Sweeps', 70.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'GREEN if used value >= 45 (midline, no laterality) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: <60° hip rotation OR <90° hip flex = Very High Risk; 30+ emphasize bridge control'),
  ('BX5', 'Guillotine from Closed Guard', 'blue', 'Submissions', NULL, NULL, NULL, NULL, 65.0, NULL, NULL, NULL, 'GREEN if used value >= 45 (midline, no laterality) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Shoulder flex <150 → inadequate choking pressure; ER <60 → RC strain under isometric load. Confidence: MEDIUM'),
  ('WX10', 'Guillotine from Half Guard (Mae Hadaka Jime)', 'white', 'Submissions', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'GREEN if used value >= 45 (midline, no laterality) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: <90° hip flex = Very High Risk; <120° shoulder flex = Very High Risk; moderate neck strain; bridge emphasis; <40° cerv ext = Very High Risk (cannot arch to finish)'),
