  ('BS19', 'Reverse De La Riva Sweep (Baby Bolo)', 'blue', 'Sweeps', 60.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'GREEN if used value >= 45 (midline, no laterality) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: Biomechanically equivalent to berimbolo with outside hook; same inversion/cervical risks; slightly less demanding than full berimbolo. Confidence: MEDIUM'),
  ('WS2', 'Flower Sweep (Pendulum Sweep)', 'white', 'Sweeps', 70.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'GREEN if used value >= 50 (midline, no laterality) after age/injury modifiers; otherwise YELLOW or RED per TechniqueEligibility formulas. RISK: <60° hip rotation = Very High Risk; <30° spinal rotation = Very High Risk; 30+ use modified swing; <45° cerv flex = Very High Risk (neck strain during roll)'),
